import React, { useState } from 'react';
import { useWebSocket } from './useWebSocket';
import './styles.css';

const STATUS_LABELS: Record<number, string> = {
  0: 'Connecting',
  1: 'Open',
  2: 'Closing',
  3: 'Closed',
};

export default function App() {
  const [input, setInput] = useState('');
  const { lastMessage, sendMessage, readyState, disconnect, connect } = useWebSocket(
    'wss://echo.websocket.org',
    { reconnect: true, reconnectInterval: 3000 }
  );

  const handleSend = () => {
    if (input.trim()) {
      sendMessage(input);
      setInput('');
    }
  };

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useWebSocket</h1>
      <p>Status: <strong data-testid="status">{STATUS_LABELS[readyState] ?? 'Unknown'}</strong></p>
      <p>Last message: <code data-testid="last-message">{lastMessage ?? '—'}</code></p>
      <div className="ws-controls">
        <input
          data-testid="send-input"
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Type a message…"
          className="ws-input"
        />
        <button data-testid="send-btn" onClick={handleSend} className="ws-btn">Send</button>
        <button data-testid="disconnect-btn" onClick={disconnect} className="ws-btn ws-btn--danger">Disconnect</button>
        <button data-testid="connect-btn" onClick={connect} className="ws-btn">Connect</button>
      </div>
    </div>
  );
}

import { useState, useRef, useCallback, useEffect } from 'react';

interface UseWebSocketOptions {
  /** Called on every incoming message */
  onMessage?: (message: string) => void;
  /** Auto-reconnect on unexpected close */
  reconnect?: boolean;
  /** Milliseconds between reconnect attempts (default 3000) */
  reconnectInterval?: number;
}

interface UseWebSocketReturn {
  lastMessage: string | null;
  sendMessage: (msg: string) => void;
  readyState: number;
  disconnect: () => void;
  connect: () => void;
}

/**
 * Custom hook for managing a WebSocket connection.
 *
 * @param url     - The WebSocket server URL
 * @param options - Configuration options
 * @returns Object with lastMessage, sendMessage, readyState, disconnect, connect
 */
export function useWebSocket(
  url: string,
  options: UseWebSocketOptions = {}
): UseWebSocketReturn {
  // TODO: Store WebSocket instance in a ref
  // TODO: Manage readyState and lastMessage as state
  // TODO: Implement connect() — create new WebSocket, wire onopen/onmessage/onclose/onerror
  // TODO: Implement sendMessage() — send if open, buffer if connecting
  // TODO: Implement disconnect() — close socket, disable reconnect
  // TODO: Handle reconnection logic in onclose
  // TODO: Clean up on unmount

  return {
    lastMessage: null,
    sendMessage: () => {},
    readyState: 3, // CLOSED
    disconnect: () => {},
    connect: () => {},
  };
}

.ws-controls {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin-top: 1rem;
}

.ws-input {
  flex: 1;
  min-width: 12rem;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  outline: none;
}

.ws-input:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59,130,246,0.15);
}

.ws-btn {
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
}

.ws-btn:hover {
  background: #e5e7eb;
}

.ws-btn--danger {
  border-color: #fca5a5;
  color: #dc2626;
}

.ws-btn--danger:hover {
  background: #fef2f2;
}

