import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React, { useState } from 'react';
import { useWebSocket } from './useWebSocket';

// --- Mock WebSocket ---
class MockWebSocket {
  static instances: MockWebSocket[] = [];
  url: string;
  readyState = 0;
  onopen: (() => void) | null = null;
  onmessage: ((e: { data: string }) => void) | null = null;
  onclose: ((e: { code: number }) => void) | null = null;
  onerror: ((e: any) => void) | null = null;
  sent: string[] = [];
  constructor(url: string) {
    this.url = url;
    MockWebSocket.instances.push(this);
  }
  send(msg: string) { this.sent.push(msg); }
  close() {
    this.readyState = 3;
    if (this.onclose) this.onclose({ code: 1000 });
  }
  simulateOpen() {
    this.readyState = 1;
    if (this.onopen) this.onopen();
  }
  simulateMessage(data: string) {
    if (this.onmessage) this.onmessage({ data });
  }
  simulateClose(code = 1006) {
    this.readyState = 3;
    if (this.onclose) this.onclose({ code });
  }
}

function Harness({ url = 'ws://test', reconnect = false }: { url?: string; reconnect?: boolean }) {
  const { lastMessage, sendMessage, readyState, disconnect, connect } = useWebSocket(url, { reconnect, reconnectInterval: 100 });
  const [input, setInput] = useState('');
  return (
    <div>
      <span data-testid="status">{readyState}</span>
      <span data-testid="last-message">{lastMessage ?? ''}</span>
      <input data-testid="send-input" value={input} onChange={e => setInput(e.target.value)} />
      <button data-testid="send-btn" onClick={() => { sendMessage(input); setInput(''); }}>Send</button>
      <button data-testid="disconnect-btn" onClick={disconnect}>Disconnect</button>
      <button data-testid="connect-btn" onClick={connect}>Connect</button>
    </div>
  );
}

describe('useWebSocket', () => {
  beforeEach(() => {
    MockWebSocket.instances = [];
    (global as any).WebSocket = MockWebSocket;
    jest.useFakeTimers();
  });
  afterEach(() => {
    jest.useRealTimers();
  });

  it('creates a WebSocket and starts in CONNECTING state', () => {
    render(<Harness />);
    expect(MockWebSocket.instances.length).toBe(1);
    expect(screen.getByTestId('status')).toHaveTextContent('0');
  });

  it('updates readyState to OPEN', () => {
    render(<Harness />);
    act(() => { MockWebSocket.instances[0].simulateOpen(); });
    expect(screen.getByTestId('status')).toHaveTextContent('1');
  });

  it('receives messages', () => {
    render(<Harness />);
    const ws = MockWebSocket.instances[0];
    act(() => { ws.simulateOpen(); });
    act(() => { ws.simulateMessage('hello'); });
    expect(screen.getByTestId('last-message')).toHaveTextContent('hello');
  });

  it('sends messages when open', () => {
    render(<Harness />);
    const ws = MockWebSocket.instances[0];
    act(() => { ws.simulateOpen(); });
    fireEvent.change(screen.getByTestId('send-input'), { target: { value: 'hi' } });
    fireEvent.click(screen.getByTestId('send-btn'));
    expect(ws.sent).toContain('hi');
  });

  it('buffers messages sent before open', () => {
    render(<Harness />);
    const ws = MockWebSocket.instances[0];
    fireEvent.change(screen.getByTestId('send-input'), { target: { value: 'early' } });
    fireEvent.click(screen.getByTestId('send-btn'));
    expect(ws.sent).toHaveLength(0);
    act(() => { ws.simulateOpen(); });
    expect(ws.sent).toContain('early');
  });

  it('disconnect closes the socket', () => {
    render(<Harness />);
    const ws = MockWebSocket.instances[0];
    act(() => { ws.simulateOpen(); });
    fireEvent.click(screen.getByTestId('disconnect-btn'));
    expect(screen.getByTestId('status')).toHaveTextContent('3');
  });

  it('reconnects when enabled and socket closes unexpectedly', () => {
    render(<Harness reconnect />);
    const ws = MockWebSocket.instances[0];
    act(() => { ws.simulateOpen(); });
    act(() => { ws.simulateClose(1006); });
    act(() => { jest.advanceTimersByTime(100); });
    expect(MockWebSocket.instances.length).toBe(2);
  });
});

