import { useState, useRef, useCallback, useEffect } from 'react';

interface UseWebSocketOptions {
  onMessage?: (message: string) => void;
  reconnect?: boolean;
  reconnectInterval?: number;
}

interface UseWebSocketReturn {
  lastMessage: string | null;
  sendMessage: (msg: string) => void;
  readyState: number;
  disconnect: () => void;
  connect: () => void;
}

export function useWebSocket(
  url: string,
  options: UseWebSocketOptions = {}
): UseWebSocketReturn {
  const { onMessage, reconnect = false, reconnectInterval = 3000 } = options;

  const [lastMessage, setLastMessage] = useState<string | null>(null);
  const [readyState, setReadyState] = useState<number>(3);

  const wsRef = useRef<WebSocket | null>(null);
  const bufferRef = useRef<string[]>([]);
  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const manualCloseRef = useRef(false);
  const mountedRef = useRef(true);

  const clearReconnectTimer = useCallback(() => {
    if (reconnectTimerRef.current !== null) {
      clearTimeout(reconnectTimerRef.current);
      reconnectTimerRef.current = null;
    }
  }, []);

  const connect = useCallback(() => {
    clearReconnectTimer();
    if (wsRef.current && wsRef.current.readyState < 2) {
      wsRef.current.close();
    }

    manualCloseRef.current = false;
    const ws = new WebSocket(url);
    wsRef.current = ws;
    setReadyState(ws.readyState);

    ws.onopen = () => {
      if (!mountedRef.current) return;
      setReadyState(1);
      // Flush buffer
      bufferRef.current.forEach(msg => ws.send(msg));
      bufferRef.current = [];
    };

    ws.onmessage = (e: any) => {
      if (!mountedRef.current) return;
      const data = typeof e.data === 'string' ? e.data : String(e.data);
      setLastMessage(data);
      onMessage?.(data);
    };

    ws.onclose = (e: any) => {
      if (!mountedRef.current) return;
      setReadyState(3);
      if (reconnect && !manualCloseRef.current) {
        reconnectTimerRef.current = setTimeout(() => {
          if (mountedRef.current) connect();
        }, reconnectInterval);
      }
    };

    ws.onerror = () => {
      if (!mountedRef.current) return;
    };
  }, [url, reconnect, reconnectInterval, onMessage, clearReconnectTimer]);

  const disconnect = useCallback(() => {
    manualCloseRef.current = true;
    clearReconnectTimer();
    if (wsRef.current) {
      wsRef.current.close();
    }
  }, [clearReconnectTimer]);

  const sendMessage = useCallback((msg: string) => {
    if (wsRef.current && wsRef.current.readyState === 1) {
      wsRef.current.send(msg);
    } else {
      bufferRef.current.push(msg);
    }
  }, []);

  useEffect(() => {
    mountedRef.current = true;
    connect();
    return () => {
      mountedRef.current = false;
      manualCloseRef.current = true;
      clearReconnectTimer();
      if (wsRef.current) {
        wsRef.current.close();
      }
    };
  }, [url]);

  return { lastMessage, sendMessage, readyState, disconnect, connect };
}
